sys_script_include.script:
var MANAssetRefQual = Class.create();
MANAssetRefQual.prototype = {
    initialize: function() {},

	//Created by : Sandesh Bhale, Created on : 22-07-2026, Purpose : For Advanced Refrence Qualifier to filter out Software Related CI's

    byAssetType: function(current) {
        var q = 'install_status!=7'; // exclude retired CIs
        if (current.asset_type == 'software') // narrow to software CIs
            q += '^sys_class_name=cmdb_ci_spkg';
        return q; // MUST return an encoded query
    },

    type: 'MANAssetRefQual'
};
